import type { CardConfig } from "../contracts/types";

export type SavedConfigOccupancyFieldHook = (config: CardConfig) => void;
export type SavedConfigOccupancyOptionHook = (options: string, config: CardConfig) => string;

export function normalizeSavedConfigOccupancy(
  config: CardConfig,
  normalizeFields: SavedConfigOccupancyFieldHook,
  normalizeOptions: SavedConfigOccupancyOptionHook,
): boolean {
  if (config.type === "door_window") {
    config.entity = "";
    normalizeFields(config);
    config.unit = "";
    config.type = "door_window";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  if (config.type === "presence") {
    config.entity = "";
    normalizeFields(config);
    config.unit = "";
    config.type = "presence";
    config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  return false;
}
